diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..311fc18c0a3f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1338,19 +1338,89 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

+  // Look through and with a negative power of 2 mask on V1 or V2. This
+  // detects idioms of the form `(x == A) || ((x & Mask) == A + 1)` where A + 1
+  // is aligned to the mask and A + 1 >= |Mask|. This pattern corresponds to a
+  // contiguous range check, which can be folded into an addition and compare.
+  // The same applies for `(x != A) && ((x & Mask) != A + 1)`.
+  auto AreContiguousRangePredicates = [](CmpPredicate Pred1, CmpPredicate Pred2,
+                                         bool IsAnd) {
+    if (IsAnd)
+      return Pred1 == ICmpInst::ICMP_NE && Pred2 == ICmpInst::ICMP_NE;
+    return Pred1 == ICmpInst::ICMP_EQ && Pred2 == ICmpInst::ICMP_EQ;
+  };
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  bool MatchedAnd1 = false, MatchedAnd2 = false;
+  if (V1 != V2 && AreContiguousRangePredicates(Pred1, Pred2, IsAnd)) {
+    Value *X;
+    if (match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask1)))) &&
+        C1->getBitWidth() == C2->getBitWidth() && *C1 == *C2 + 1 &&
+        C1->uge(Mask1->abs()) && C1->isPowerOf2()) {
+      MatchedAnd1 = true;
+      V1 = X;
+    }
+    if (match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask2)))) &&
+        C1->getBitWidth() == C2->getBitWidth() && *C2 == *C1 + 1 &&
+        C2->uge(Mask2->abs()) && C2->isPowerOf2()) {
+      MatchedAnd2 = true;
+      V2 = X;
+    }
+  }
+
   if (V1 != V2)
     return nullptr;

-  ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+  ConstantRange CR1 =
+      MatchedAnd1
+          ? ConstantRange(*C1, *C1 - *Mask1)
+          : ConstantRange::makeExactICmpRegion(
+                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);

-  ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+  // If the comparison was on (X & M) rather than X directly, expand the
+  // range to account for the bits not covered by the mask.
+  if (Mask1) {
+    APInt NotM = ~*Mask1;
+    if (!NotM.isZero() && (NotM + 1).isPowerOf2()) {
+      ICmpInst::Predicate EffPred1 =
+          IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1;
+      if ((*C1 & NotM) != 0) {
+        CR1 = EffPred1 == ICmpInst::ICMP_EQ
+                  ? ConstantRange::getEmpty(C1->getBitWidth())
+                  : ConstantRange::getFull(C1->getBitWidth());
+      } else {
+        CR1 = ConstantRange(*C1, (*C1 | NotM) + 1);
+        if (EffPred1 == ICmpInst::ICMP_NE)
+          CR1 = CR1.inverse();
+      }
+    }
+  }
+
+  ConstantRange CR2 =
+      MatchedAnd2
+          ? ConstantRange(*C2, *C2 - *Mask2)
+          : ConstantRange::makeExactICmpRegion(
+                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

+  if (Mask2) {
+    APInt NotM = ~*Mask2;
+    if (!NotM.isZero() && (NotM + 1).isPowerOf2()) {
+      ICmpInst::Predicate EffPred2 =
+          IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2;
+      if ((*C2 & NotM) != 0) {
+        CR2 = EffPred2 == ICmpInst::ICMP_EQ
+                  ? ConstantRange::getEmpty(C2->getBitWidth())
+                  : ConstantRange::getFull(C2->getBitWidth());
+      } else {
+        CR2 = ConstantRange(*C2, (*C2 | NotM) + 1);
+        if (EffPred2 == ICmpInst::ICMP_NE)
+          CR2 = CR2.inverse();
+      }
+    }
+  }
   Type *Ty = V1->getType();
   Value *NewV = V1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);

log.expect_optimized_program:
define i1 @and_icmp_ne_and_pow2_commute(i32 %x) {
  %1 = add i32 %x, -160
  %ret = icmp ult i32 %1, -33
  ret i1 %ret
}

